import {useEffect,useState} from 'react';
import { fetchProducts } from '../api/apiService';

function Home() {
  const [products,setProducts]=useState([]);

  useEffect(()=>{
    fetchProducts().then((data)=>setProducts(data));
    },[]);

    return (
        <div>
            {products.map(p => (
                <div key={p.id}>
                    <h3>{p.name}</h3>
                    <p>LKR {p.price}</p>
                </div>
            ))}
        </div>
    );
}

export default Home;
